UPDATE TB_RESERVATION
   SET STATUS_CD = #{statusCd},
       REJECT_REASON = #{rejectReason, jdbcType=VARCHAR}
 WHERE RESV_ID   = #{resvId}
   AND TARGET_ID = TO_CHAR(#{hospitalId})
   AND RESV_TYPE = 'HOSPITAL'

mapper.select:
SELECT NAME
  FROM TB_HOSPITAL
 WHERE HOSPITAL_ID = #{hospitalId}
